external_knowledge:
- Significant return ratio in this context is defined as greater than 10;
- The total value locked represents the total amount of assets in a liquidity pool;
- The total trading volume indicates the total value of trades executed in the pool.

sql:
SELECT AVG(balance) 
FROM pool_tokens 
WHERE pool_id = (SELECT pool_id FROM liquidity_pools WHERE name = 'Pool 2');

SELECT lp.pool_id, lp.name, lp.total_value_locked, (SELECT AVG(total_value_locked) FROM liquidity_pools) as average_value_locked
FROM liquidity_pools lp
WHERE lp.total_value_locked > (SELECT AVG(total_value_locked) FROM liquidity_pools);

SELECT COUNT(pool_id) AS failed_performance_audits
FROM pool_audits
WHERE audit_type = 'performance' AND audit_result = 'fail';

SELECT SUM(total_fees_earned) AS total_fees_earned_by_providers
FROM liquidity_providers
WHERE pool_id IN (
  SELECT pool_id
  FROM liquidity_pools
  WHERE total_fees_collected > (
    SELECT AVG(total_fees_collected)
    FROM liquidity_pools
  )
);

SELECT provider_id, SUM(total_liquidity_provided) AS total_liquidity
FROM liquidity_providers
GROUP BY provider_id;

SELECT name, COUNT(pool_id) AS num_pools
FROM liquidity_pools
GROUP BY name;

SELECT * 
FROM liquidity_providers 
WHERE total_liquidity_provided < 1500;

SELECT alert_id, alert_type
FROM pool_alerts
WHERE pool_id = 1;

SELECT AVG(trading_volume) AS average_trading_volume
FROM liquidity_pools
WHERE total_value_locked > 100000000;

external_knowledge:
Significant trading activity is defined as a total trading volume of at least 1000 units; 24-hour trading volume greater than zero means the pair has had at least one trade in the past 24 hours.;
Liquidity pools are platforms that allow users to trade cryptocurrencies directly, matching buy and sell orders without needing an intermediary.;
The total trading volume is a sum of the amounts of all trades for a specific pair within a liquidity pool over a given period.;

sql:
SELECT COUNT(*)
FROM impermanent_losses
WHERE loss_percentage > 0.5;

SELECT name, description, total_value_locked, trading_volume
FROM liquidity_pools
WHERE trading_volume > (SELECT AVG(trading_volume) FROM liquidity_pools);

SELECT SUM(total_liquidity_provided) AS total_liquidity_provided
FROM liquidity_providers
WHERE total_liquidity_provided > 500;

SELECT name
FROM liquidity_pools
WHERE total_value_locked = (SELECT MAX(total_value_locked) FROM liquidity_pools);

SELECT pool_id, name, total_value_locked, total_fees_collected, trading_volume
FROM liquidity_pools
WHERE total_fees_collected > 10 AND pool_id > 100;

SELECT provider_id, pool_id, address, created_at, updated_at, total_liquidity_provided, total_fees_earned
FROM liquidity_providers
WHERE provider_id = 0;
